(1164,'KIMIA_XII','KIM','G',1,26,'',0,'<p style=\"text-align:justify;\">Diketahui Persamaan reaksi redoks:</p><p><i><strong>&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; &nbsp; &nbsp;a</strong></i> Fe(s) + <i><strong>b</strong></i>&nbsp;NO<sub>3</sub><sup>–</sup> (aq) +&nbsp;H<sup>+</sup><sub>(aq)</sub> →&nbsp;&nbsp;H<sub>2</sub>O<i><sub>(l)</sub></i> + <i><strong>c</strong></i> Fe<sup>2+</sup><sub>(aq)</sub>&nbsp;+&nbsp;&nbsp;<i><strong>d</strong></i>&nbsp;NH<sub>4</sub><sup>+</sup><sub>(aq)</sub></p><p>Harga koefisien a, b, c, dan d berturut-turut adalah ....</p>','','','','<p>1, 1,&nbsp;4, dan 4</p>','<p>2, 1,&nbsp;4, dan 4</p>','<p>4, 1, 2, dan 4</p>','<p>4,&nbsp;1, 4, dan 1</p>','<p>4, 2, 1, dan 4</p>','','','','','',3,'Y','Y'),
